public class Collatz {
    public static int steps(int n) {
        int count = 0;
        while (n != 1) {
            if (n % 2 == 0) n /= 2;
            else            n = 3 * n + 1;
            count++;
        }
        return count;
    }
    public static void main(String[] args) {
        System.out.println(steps(6));
        System.out.println(steps(1));
    }
}
